import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { TechType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// モデルは基本のタスクに適したFlashを使用
const MODEL_NAME = 'gemini-3-flash-preview';

export const getLessonExplanation = async (tech: TechType, topic: string): Promise<string> => {
  try {
    const prompt = `
      あなたは親切でフレンドリーなプログラミングの先生です。
      プログラミング完全初心者に向けて、以下のトピックについて150文字以内で優しく解説してください。
      専門用語はなるべく避け、例え話などを使ってわかりやすく説明してください。

      技術: ${tech}
      トピック: ${topic}

      レスポンスはMarkdown形式で返してください。
    `;

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
    });

    return response.text || "ごめんなさい、今の説明がうまく読み込めませんでした。もう一度試してみてね！";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "AI先生がちょっと休憩中です。後でもう一度呼んでね。";
  }
};

export const checkCodeWithAI = async (
  task: string,
  code: string,
  tech: TechType
): Promise<{ passed: boolean; feedback: string }> => {
  try {
    const prompt = `
      あなたは初心者を励ますプログラミングの先生です。
      生徒が以下の課題に取り組み、コードを書きました。
      コードが課題の要件を満たしているか判定し、優しくフィードバックをしてください。

      【課題】
      ${task}

      【技術】
      ${tech}

      【生徒のコード】
      ${code}

      レスポンスは以下のJSON形式のみで返してください。余計な説明は不要です。
      {
        "passed": boolean, // 課題をクリアしているか
        "feedback": string // 褒める言葉、または修正のアドバイス（日本語で、フレンドリーに）
      }
    `;

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text");

    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      passed: false,
      feedback: "採点中にエラーが起きちゃったみたい。コードは合ってるかな？もう一度確認してみてね！"
    };
  }
};

export const askTutor = async (question: string, contextCode: string): Promise<string> => {
   try {
    const prompt = `
      あなたは「WebKiso」という学習サイトのフレンドリーなAIキャラクターです。
      生徒からの質問に答えてください。

      【生徒のコード状況】
      ${contextCode}

      【生徒の質問】
      ${question}

      短く、励ますような口調で、ヒントを与えてください。答えをそのまま教えるのではなく、気づきを与えてください。
    `;

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
    });

    return response.text || "うんうん、それは難しいところだよね。";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "ごめんね、ちょっと声が届かなかったみたい。もう一回聞いてみて！";
  }
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  isLoading,
  ...props 
}) => {
  const baseStyle = "inline-flex items-center justify-center rounded-xl font-bold transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-md hover:shadow-lg focus:ring-indigo-500",
    secondary: "bg-emerald-500 text-white hover:bg-emerald-600 shadow-md hover:shadow-lg focus:ring-emerald-500",
    outline: "border-2 border-slate-200 text-slate-600 hover:border-indigo-300 hover:text-indigo-600 hover:bg-indigo-50",
    ghost: "text-slate-500 hover:text-indigo-600 hover:bg-indigo-50"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-5 py-2.5 text-base",
    lg: "px-8 py-3.5 text-lg"
  };

  return (
    <button 
      className={`${baseStyle} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          考え中...
        </>
      ) : children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { TechType } from '../types';

interface CodeEditorProps {
  initialCode: string;
  tech: TechType;
  onChange: (code: string) => void;
  onRun: () => void;
  isCorrect?: boolean | null;
}

export const CodeEditor: React.FC<CodeEditorProps> = ({ initialCode, tech, onChange, onRun, isCorrect }) => {
  const [code, setCode] = useState(initialCode);

  useEffect(() => {
    setCode(initialCode);
  }, [initialCode]);

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newCode = e.target.value;
    setCode(newCode);
    onChange(newCode);
  };

  const getLanguageColor = () => {
    switch (tech) {
      case TechType.HTML: return 'text-orange-500';
      case TechType.CSS: return 'text-blue-500';
      case TechType.JS: return 'text-yellow-500';
      default: return 'text-slate-500';
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 rounded-2xl overflow-hidden shadow-2xl border-4 border-slate-800">
      <div className="flex items-center justify-between px-4 py-3 bg-slate-800 border-b border-slate-700">
        <div className="flex items-center gap-2">
          <div className="flex gap-1.5">
            <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
          </div>
          <span className={`ml-3 font-mono text-sm font-bold ${getLanguageColor()}`}>
            {tech === TechType.JS ? 'main.js' : tech === TechType.CSS ? 'style.css' : 'index.html'}
          </span>
        </div>
        {isCorrect === true && (
          <span className="text-emerald-400 text-xs font-bold px-2 py-1 bg-emerald-900/30 rounded-full animate-pulse">
            ✨ クリア！
          </span>
        )}
      </div>

      <div className="flex-1 relative group">
        <textarea
          value={code}
          onChange={handleChange}
          className="w-full h-full p-4 bg-slate-900 text-slate-100 font-mono text-sm resize-none focus:outline-none leading-relaxed selection:bg-indigo-500/30"
          spellCheck={false}
          placeholder="ここにコードを書いてね..."
        />
      </div>

      <div className="p-2 bg-slate-800 border-t border-slate-700 flex justify-end">
        <button
          onClick={onRun}
          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg font-bold text-sm transition-colors"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          実行してチェック
        </button>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { TechType } from '../types';

interface PreviewProps {
  code: string;
  tech: TechType;
}

export const Preview: React.FC<PreviewProps> = ({ code, tech }) => {

  const srcDoc = useMemo(() => {
    // 簡易的なプレビュー生成ロジック
    let content = '';

    if (tech === TechType.HTML) {
      content = `
        <!DOCTYPE html>
        <html>
          <head>
             <style>body { font-family: sans-serif; padding: 1rem; color: #333; }</style>
          </head>
          <body>
            ${code}
          </body>
        </html>
      `;
    } else if (tech === TechType.CSS) {
      content = `
        <!DOCTYPE html>
        <html>
          <head>
            <style>
              body { font-family: sans-serif; padding: 1rem; color: #333; }
              ${code}
            </style>
          </head>
          <body>
            <h1>見出しのサンプル</h1>
            <p>これは段落のサンプルテキストです。CSSでどう変わるかな？</p>
            <div class="box">ボックス要素</div>
          </body>
        </html>
      `;
    } else if (tech === TechType.JS) {
      content = `
        <!DOCTYPE html>
        <html>
          <head>
             <style>body { font-family: sans-serif; padding: 1rem; color: #333; }</style>
          </head>
          <body>
            <h3>JavaScript コンソール</h3>
            <p>結果はアラートまたはコンソールに出ます（F12は使わずに簡易表示します）</p>
            <div id="output" style="background: #f0f0f0; padding: 10px; border-radius: 4px; font-family: monospace; margin-top: 10px;"></div>
            <script>
              // console.logを上書きして画面に表示
              const originalLog = console.log;
              const output = document.getElementById('output');
              console.log = function(...args) {
                output.innerHTML += '<div>> ' + args.join(' ') + '</div>';
                originalLog.apply(console, args);
              };

              try {
                ${code}
              } catch (e) {
                console.log("Error: " + e.message);
              }
            </script>
          </body>
        </html>
      `;
    }
    return content;
  }, [code, tech]);

  return (
    <div className="h-full bg-white rounded-2xl overflow-hidden shadow-lg border border-slate-200 flex flex-col">
       <div className="bg-slate-100 px-4 py-2 border-b border-slate-200 flex justify-between items-center">
         <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Preview</span>
         <div className="flex gap-1">
           <div className="w-2 h-2 rounded-full bg-slate-300"></div>
           <div className="w-2 h-2 rounded-full bg-slate-300"></div>
         </div>
       </div>
       <iframe
        title="preview"
        srcDoc={srcDoc}
        className="w-full flex-1 border-none bg-white"
        sandbox="allow-scripts"
      />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CURRICULUM } from './constants';
import { Lesson, CourseModule, ChatMessage } from './types';
import { checkCodeWithAI, getLessonExplanation, askTutor } from './services/geminiService';
import { Button } from './components/Button';
import { CodeEditor } from './components/CodeEditor';
import { Preview } from './components/Preview';

export default function App() {
  const [activeModuleId, setActiveModuleId] = useState<string | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [code, setCode] = useState<string>("");

  // AI State
  const [explanation, setExplanation] = useState<string>("");
  const [isLoadingExplanation, setIsLoadingExplanation] = useState(false);
  const [isChecking, setIsChecking] = useState(false);
  const [feedback, setFeedback] = useState<{ passed: boolean; feedback: string } | null>(null);

  // Chat State
  const [showChat, setShowChat] = useState(false);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState("");
  const [isChatting, setIsChatting] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const activeModule = CURRICULUM.find(m => m.id === activeModuleId);
  const activeLesson = activeModule?.lessons.find(l => l.id === activeLessonId);

  useEffect(() => {
    if (activeLesson) {
      setCode(activeLesson.defaultCode);
      setFeedback(null);
      setChatMessages([{ role: 'model', text: '何か困ったことがあったら、いつでも聞いてね！' }]);
      loadExplanation(activeLesson);
    }
  }, [activeLesson]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, showChat]);

  const loadExplanation = async (lesson: Lesson) => {
    setIsLoadingExplanation(true);
    const text = await getLessonExplanation(lesson.tech, lesson.title);
    setExplanation(text);
    setIsLoadingExplanation(false);
  };

  const handleRunAndCheck = async () => {
    if (!activeLesson) return;
    setIsChecking(true);
    setFeedback(null);
    const result = await checkCodeWithAI(activeLesson.task, code, activeLesson.tech);
    setFeedback(result);
    setIsChecking(false);
  };

  const handleChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isChatting) return;

    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput("");
    setIsChatting(true);

    const reply = await askTutor(userMsg, code);
    setChatMessages(prev => [...prev, { role: 'model', text: reply }]);
    setIsChatting(false);
  };

  // --- Views ---

  if (!activeModuleId) {
    return (
      <div className="min-h-screen bg-slate-50 p-6 md:p-12">
        <div className="max-w-5xl mx-auto">
          <header className="mb-12 text-center">
            <h1 className="text-4xl md:text-5xl font-black text-slate-800 mb-4 tracking-tight">
              Web<span className="text-indigo-600">Kiso</span>
            </h1>
            <p className="text-xl text-slate-500 font-medium">
              作って学ぶ、はじめてのWebプログラミング。
            </p>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {CURRICULUM.map((module) => (
              <button
                key={module.id}
                onClick={() => {
                  setActiveModuleId(module.id);
                  setActiveLessonId(module.lessons[0].id);
                }}
                className="group relative flex flex-col text-left bg-white rounded-3xl p-8 shadow-sm hover:shadow-xl transition-all duration-300 border-2 border-transparent hover:border-indigo-100 hover:-translate-y-1"
              >
                <div className={`w-16 h-16 rounded-2xl ${module.color} flex items-center justify-center text-3xl mb-6 group-hover:scale-110 transition-transform`}>
                  {module.icon}
                </div>
                <h2 className="text-2xl font-bold text-slate-800 mb-2 group-hover:text-indigo-600 transition-colors">
                  {module.title}
                </h2>
                <p className="text-slate-400 font-medium">
                  {module.lessons.length} レッスン
                </p>
                <div className="mt-6 flex items-center text-indigo-500 font-bold opacity-0 group-hover:opacity-100 transition-opacity -translate-x-2 group-hover:translate-x-0">
                  始める <span className="ml-2">→</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col bg-slate-50 overflow-hidden">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-3 flex items-center justify-between shadow-sm z-10">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setActiveModuleId(null)}
            className="text-slate-400 hover:text-indigo-600 transition-colors"
          >
            ← コース一覧
          </button>
          <div className="flex items-center gap-3">
             <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-lg ${activeModule?.color}`}>
                {activeModule?.icon}
             </div>
             <h1 className="font-bold text-slate-800">{activeModule?.title}</h1>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <span className="text-sm text-slate-500 font-bold mr-2 hidden md:inline">
             Lesson:
           </span>
           <div className="flex gap-1">
             {activeModule?.lessons.map((l) => (
               <button
                 key={l.id}
                 onClick={() => setActiveLessonId(l.id)}
                 className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all
                   ${activeLessonId === l.id 
                     ? 'bg-indigo-600 text-white scale-110 shadow-md' 
                     : 'bg-slate-100 text-slate-400 hover:bg-indigo-100 hover:text-indigo-500'}`}
               >
                 {activeModule.lessons.indexOf(l) + 1}
               </button>
             ))}
           </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden">

        {/* Left Panel: Content */}
        <div className="w-full md:w-1/3 flex flex-col border-r border-slate-200 bg-white z-0">
          <div className="flex-1 overflow-y-auto p-6 md:p-8">
            <span className="inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-xs font-bold mb-4">
              {activeLesson?.tech}
            </span>
            <h2 className="text-3xl font-black text-slate-800 mb-6 leading-tight">
              {activeLesson?.title}
            </h2>

            <div className="prose prose-slate prose-lg mb-8">
              {isLoadingExplanation ? (
                 <div className="animate-pulse space-y-3">
                   <div className="h-4 bg-slate-200 rounded w-3/4"></div>
                   <div className="h-4 bg-slate-200 rounded w-full"></div>
                   <div className="h-4 bg-slate-200 rounded w-5/6"></div>
                 </div>
              ) : (
                <div className="whitespace-pre-wrap text-slate-600 leading-relaxed">
                  {explanation}
                </div>
              )}
            </div>

            <div className="bg-indigo-50 border-l-4 border-indigo-500 p-6 rounded-r-xl mb-8">
              <h3 className="font-bold text-indigo-900 mb-2 flex items-center gap-2">
                🎯 今日のミッション
