import React, { useState, useEffect, useRef } from 'react';
import { TechType } from '../types';

interface CodeEditorProps {
  initialCode: string;
  tech: TechType;
  onChange: (code: string) => void;
  onRun: () => void;
  isCorrect?: boolean | null;
}

// 簡易的な補完候補リスト
const SUGGESTIONS = {
  [TechType.HTML]: ['<h1>', '</h1>', '<p>', '</p>', '<button>', '</button>', '<div>', '</div>', '<span>', '</span>', 'class="', 'id="'],
  [TechType.CSS]: ['color', 'background-color', 'font-size', 'width', 'height', 'padding', 'margin', 'border', 'text-align: center', 'display: flex'],
  [TechType.JS]: ['alert()', 'console.log()', 'document.getElementById()', 'const', 'let', 'function', 'if () {}', 'return']
};

export const CodeEditor: React.FC<CodeEditorProps> = ({ initialCode, tech, onChange, onRun, isCorrect }) => {
  const [code, setCode] = useState(initialCode);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    setCode(initialCode);
  }, [initialCode]);

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newCode = e.target.value;
    setCode(newCode);
    onChange(newCode);

    // Simple Autocomplete Logic
    handleAutocomplete(newCode, e.target.selectionStart);
  };

  const handleAutocomplete = (currentCode: string, cursorPosition: number) => {
    // カーソル直前の単語を取得する簡易ロジック
    const textBeforeCursor = currentCode.slice(0, cursorPosition);
    const words = textBeforeCursor.split(/[\s\n<>(){}:;]/); // 区切り文字で分割
    const lastWord = words[words.length - 1];

    if (lastWord.length < 1) {
      setSuggestions([]);
      return;
    }

    const candidates = SUGGESTIONS[tech];
    const matches = candidates.filter(s => s.toLowerCase().startsWith(lastWord.toLowerCase()) && s !== lastWord);
    setSuggestions(matches.slice(0, 5)); // 最大5件表示
  };

  const applySuggestion = (suggestion: string) => {
    const cursorPosition = textareaRef.current?.selectionStart || 0;
    const textBeforeCursor = code.slice(0, cursorPosition);
    const textAfterCursor = code.slice(cursorPosition);

    // 直前の入力中単語を探して置換
    const words = textBeforeCursor.split(/[\s\n<>(){}:;]/);
    const lastWord = words[words.length - 1];
    const prefix = textBeforeCursor.slice(0, -lastWord.length); // 入力中単語を除いた部分

    const newCode = prefix + suggestion + textAfterCursor;

    setCode(newCode);
    onChange(newCode);
    setSuggestions([]);

    // カーソル位置を修正（Reactの再レンダリング後にフォーカスを戻す）
    setTimeout(() => {
        if (textareaRef.current) {
            textareaRef.current.focus();
            const newCursorPos = prefix.length + suggestion.length;
            textareaRef.current.setSelectionRange(newCursorPos, newCursorPos);
        }
    }, 0);
  };

  const getLanguageColor = () => {
    switch (tech) {
      case TechType.HTML: return 'text-orange-500';
      case TechType.CSS: return 'text-blue-500';
      case TechType.JS: return 'text-yellow-500';
      default: return 'text-slate-500';
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 rounded-2xl overflow-hidden shadow-2xl border-4 border-slate-800 relative">
      <div className="flex items-center justify-between px-4 py-3 bg-slate-800 border-b border-slate-700">
        <div className="flex items-center gap-2">
          <div className="flex gap-1.5">
            <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
          </div>
          <span className={`ml-3 font-mono text-sm font-bold ${getLanguageColor()}`}>
            {tech === TechType.JS ? 'main.js' : tech === TechType.CSS ? 'style.css' : 'index.html'}
          </span>
        </div>
        {isCorrect === true && (
          <span className="text-emerald-400 text-xs font-bold px-2 py-1 bg-emerald-900/30 rounded-full animate-pulse">
            ✨ クリア！
          </span>
        )}
      </div>

      <div className="flex-1 relative group">
        <textarea
          ref={textareaRef}
          value={code}
          onChange={handleChange}
          className="w-full h-full p-4 bg-slate-900 text-slate-100 font-mono text-sm resize-none focus:outline-none leading-relaxed selection:bg-indigo-500/30"
          spellCheck={false}
          placeholder="ここにコードを書いてね..."
        />

        {/* Autocomplete Suggestions Overlay */}
        {suggestions.length > 0 && (
            <div className="absolute bottom-4 left-4 flex gap-2 z-10 animate-fade-in-up">
                <div className="bg-slate-800 border border-slate-600 rounded-lg shadow-xl p-1 text-xs text-slate-400 flex flex-col gap-1 min-w-[120px]">
                    <span className="px-2 py-1 border-b border-slate-700 font-bold text-[10px] uppercase">Suggestions</span>
                    {suggestions.map((s, idx) => (
                        <button 
                            key={idx}
                            onClick={() => applySuggestion(s)}
                            className="text-left px-2 py-1.5 hover:bg-indigo-600 hover:text-white rounded text-slate-200 font-mono transition-colors"
                        >
                            {s}
                        </button>
                    ))}
                    <div className="px-2 py-1 text-[10px] opacity-50 text-right">Tab or Click</div>
                </div>
            </div>
        )}
      </div>

      <div className="p-2 bg-slate-800 border-t border-slate-700 flex justify-end">
        <button
          onClick={onRun}
          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg font-bold text-sm transition-colors"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          実行してチェック
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CURRICULUM } from './constants';
import { Button } from './components/Button';
import { CodeEditor } from './components/CodeEditor';
import { Preview } from './components/Preview';

export default function App() {
  const [activeModuleId, setActiveModuleId] = useState<string | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [code, setCode] = useState<string>("");

  // State
  const [isChecking, setIsChecking] = useState(false);
  const [feedback, setFeedback] = useState<{ passed: boolean; feedback: string } | null>(null);
  const [showHint, setShowHint] = useState(false);

  const activeModule = CURRICULUM.find(m => m.id === activeModuleId);
  const activeLesson = activeModule?.lessons.find(l => l.id === activeLessonId);

  useEffect(() => {
    if (activeLesson) {
      setCode(activeLesson.defaultCode);
      setFeedback(null);
      setShowHint(false);
    }
  }, [activeLesson]);

  const handleRunAndCheck = async () => {
    if (!activeLesson) return;
    setIsChecking(true);
    setFeedback(null);

    // Simulate a short delay for "thinking" feel
    await new Promise(resolve => setTimeout(resolve, 500));

    // Use local validation logic defined in constants
    const result = activeLesson.validate(code);

    setFeedback(result);
    setIsChecking(false);
  };

  // --- Views ---

  if (!activeModuleId) {
    return (
      <div className="min-h-screen bg-slate-50 p-6 md:p-12">
        <div className="max-w-5xl mx-auto">
          <header className="mb-12 text-center">
            <h1 className="text-4xl md:text-5xl font-black text-slate-800 mb-4 tracking-tight">
              Web<span className="text-indigo-600">Kiso</span>
            </h1>
            <p className="text-xl text-slate-500 font-medium">
              作って学ぶ、はじめてのWebプログラミング。
            </p>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {CURRICULUM.map((module) => (
              <button
                key={module.id}
                onClick={() => {
                  setActiveModuleId(module.id);
                  setActiveLessonId(module.lessons[0].id);
                }}
                className="group relative flex flex-col text-left bg-white rounded-3xl p-8 shadow-sm hover:shadow-xl transition-all duration-300 border-2 border-transparent hover:border-indigo-100 hover:-translate-y-1"
              >
                <div className={`w-16 h-16 rounded-2xl ${module.color} flex items-center justify-center text-3xl mb-6 group-hover:scale-110 transition-transform`}>
                  {module.icon}
                </div>
                <h2 className="text-2xl font-bold text-slate-800 mb-2 group-hover:text-indigo-600 transition-colors">
                  {module.title}
                </h2>
                <p className="text-slate-400 font-medium">
                  {module.lessons.length} レッスン
                </p>
                <div className="mt-6 flex items-center text-indigo-500 font-bold opacity-0 group-hover:opacity-100 transition-opacity -translate-x-2 group-hover:translate-x-0">
                  始める <span className="ml-2">→</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col bg-slate-50 overflow-hidden">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-3 flex items-center justify-between shadow-sm z-10">
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setActiveModuleId(null)}
            className="text-slate-400 hover:text-indigo-600 transition-colors"
          >
            ← コース一覧
          </button>
          <div className="flex items-center gap-3">
             <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-lg ${activeModule?.color}`}>
                {activeModule?.icon}
             </div>
             <h1 className="font-bold text-slate-800">{activeModule?.title}</h1>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <span className="text-sm text-slate-500 font-bold mr-2 hidden md:inline">
             Lesson:
           </span>
           <div className="flex gap-1">
             {activeModule?.lessons.map((l) => (
               <button
                 key={l.id}
                 onClick={() => setActiveLessonId(l.id)}
                 className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all
                   ${activeLessonId === l.id 
                     ? 'bg-indigo-600 text-white scale-110 shadow-md' 
                     : 'bg-slate-100 text-slate-400 hover:bg-indigo-100 hover:text-indigo-500'}`}
               >
                 {activeModule.lessons.indexOf(l) + 1}
               </button>
             ))}
           </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden">

        {/* Left Panel: Content */}
        <div className="w-full md:w-1/3 flex flex-col border-r border-slate-200 bg-white z-0">
          <div className="flex-1 overflow-y-auto p-6 md:p-8">
            <span className="inline-block px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-xs font-bold mb-4">
              {activeLesson?.tech}
            </span>
            <h2 className="text-3xl font-black text-slate-800 mb-6 leading-tight">
              {activeLesson?.title}
            </h2>

            <div className="prose prose-slate prose-lg mb-8">
              <div className="whitespace-pre-wrap text-slate-600 leading-relaxed">
                  {activeLesson?.explanation}
              </div>
            </div>

            <div className="bg-indigo-50 border-l-4 border-indigo-500 p-6 rounded-r-xl mb-8">
              <h3 className="font-bold text-indigo-900 mb-2 flex items-center gap-2">
                🎯 今日のミッション
              </h3>
              <p className="text-indigo-800 font-medium">
                {activeLesson?.task}
              </p>
            </div>

            {/* Hint Section */}
            {activeLesson?.hints && activeLesson.hints.length > 0 && (
                <div className="mb-8">
                    {!showHint ? (
                        <Button 
                            variant="ghost" 
                            size="sm"
                            onClick={() => setShowHint(true)}
                            className="text-slate-400 hover:text-indigo-500"
                        >
                            💡 ヒントを見る
                        </Button>
                    ) : (
                        <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4 animate-fade-in">
                            <h4 className="font-bold text-yellow-800 mb-2 flex items-center gap-2">
                                💡 ヒント
                            </h4>
                            <ul className="list-disc list-inside space-y-1 text-yellow-800/80 text-sm">
                                {activeLesson.hints.map((hint, i) => (
                                    <li key={i}>{hint}</li>
                                ))}
                            </ul>
                        </div>
                    )}
                </div>
            )}

            {/* Validation Feedback Area */}
            {feedback && (
              <div className={`p-6 rounded-xl border-2 mb-8 animate-fade-in ${feedback.passed ? 'bg-emerald-50 border-emerald-200' : 'bg-orange-50 border-orange-200'}`}>
                <div className="flex items-start gap-4">
                   <div className={`text-2xl ${feedback.passed ? 'animate-bounce' : ''}`}>
                     {feedback.passed ? '🎉' : '🤔'}
                   </div>
                   <div>
                     <h4 className={`font-bold mb-1 ${feedback.passed ? 'text-emerald-800' : 'text-orange-800'}`}>
                       {feedback.passed ? '正解！' : '惜しい！'}
                     </h4>
                     <p className={`text-sm ${feedback.passed ? 'text-emerald-700' : 'text-orange-700'}`}>
                       {feedback.feedback}
                     </p>
                   </div>
                </div>
                {feedback.passed && (
                  <div className="mt-4">
                    <Button 
                      variant="secondary" 
                      onClick={() => {
                         const currentIndex = activeModule!.lessons.findIndex(l => l.id === activeLessonId);
                         if (currentIndex < activeModule!.lessons.length - 1) {
                           setActiveLessonId(activeModule!.lessons[currentIndex + 1].id);
                         } else {
                           alert("このコースはすべて完了です！おめでとうございます！");
                           setActiveModuleId(null);
                         }
                      }}
                    >
                      次のレッスンへ進む →
                    </Button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Right Panel: Editor & Preview */}
        <div className="w-full md:w-2/3 bg-slate-100 p-4 gap-4 grid grid-rows-2 md:grid-rows-1 md:grid-cols-2 relative">

           {/* Code Editor */}
           <div className="h-full">
              {activeLesson && (
                <CodeEditor
                  tech={activeLesson.tech}
                  initialCode={code}
                  onChange={setCode}
                  onRun={handleRunAndCheck}
                  isCorrect={feedback?.passed}
                />
              )}
           </div>

           {/* Preview */}
           <div className="h-full hidden md:block">
              {activeLesson && <Preview code={code} tech={activeLesson.tech} />}
           </div>
        </div>
      </main>
    </div>
  );
}
